<?phpnamespace App\Http\Controllers\Api\Rider;use App\Models\ServiceArea;use App\Models\City;use App\Models\Rider;use App\Models\Currency;use App\Models\DeliveryRider;use App\Models\FavoriteSeller;use App\Models\Order;use App\Models\PaymentGateway;use App\Models\RiderServiceArea;use Illuminate\Http\Request;use Illuminate\Support\Facades\Hash;use App\Http\Resources\ServiceAreaResource;use Validator;class RiderController{    // public function updateServiceArea(Request $request)    // {    //     try {    //         $request->validate([    //             'area' => 'nullable|exists:service_areas,id'    //         ]);    //         $rider = Rider::find(auth('rider-api')->user()->id);    //             $rider->service_area_id=$request->area;    //         $rider->save();    //         $data=null;    //         if ($request->area) {    //             $service_area = new ServiceAreaResource($rider->serviceArea);    //             $data['service_area']=$service_area;    //             $message="Updated successfully";    //         } else {    //             $service_area = null;    //             $message="Deleted successfully";    //         }    //         return response()->json(['status' => true, 'message' => $message, 'data' => $data]);    //     }catch(\Exception $e){    //         dd($e);    //         return response()->json(['status' => false, 'message' => 'Something went wrong'],500);    //     }    // }            public function storeServiceArea(Request $request)    {        $request->validate([            'area' => 'required|exists:service_areas,id'        ]);        $rider = auth('rider-api')->user();        $exists = RiderServiceArea::where('rider_id', $rider->id)            ->where('service_area_id', $request->area)            ->first();        if ($exists) {            return response()->json([                'status' => false,                'message' => 'Service area already added.'            ], 409);        }        $riderServiceArea = RiderServiceArea::create([            'rider_id' => $rider->id,            'service_area_id' => $request->area        ]);        return response()->json([            'status' => true,            'message' => 'Service area added successfully.',            'data' => new ServiceAreaResource($riderServiceArea->serviceArea)        ]);    }        // public function deleteServiceArea($id)    // {    //     $rider = auth('rider-api')->user();    //     $area = RiderServiceArea::where('rider_id', $rider->id)    //         ->where('id', $id)    //         ->first();    //     if (!$area) {    //         return response()->json([    //             'status' => false,    //             'message' => 'Service area not found.'    //         ], 404);    //     }    //     $area->delete();    //     return response()->json([    //         'status' => true,    //         'message' => 'Service area deleted successfully.'    //     ]);    // }        public function deleteServiceArea($id){    try {        // Get authenticated rider        $rider = auth('rider-api')->user();        // Find the service area record by rider_id + service_area_id        $area = RiderServiceArea::where('rider_id', $rider->id)            ->where('service_area_id', $id)  // 👈 match by service_area_id instead of id            ->first();        // If not found, return clear response        if (!$area) {            return response()->json([                'status' => false,                'message' => 'Service area not found for this rider.'            ], 404);        }        // Delete the record        $area->delete();        // Return success response        return response()->json([            'status' => true,            'message' => 'Service area deleted successfully.'        ]);    } catch (\Exception $e) {        return response()->json([            'status' => false,            'message' => 'Something went wrong',            'error' => $e->getMessage()        ], 500);    }}    public function updateServiceArea(Request $request){    try {        // ✅ Validate that both old and new service area IDs exist in the service_areas table        $request->validate([            'id' => 'required|exists:service_areas,id',   // old area id            'area' => 'required|exists:service_areas,id'  // new area id        ]);        // ✅ Get authenticated rider        $rider = auth('rider-api')->user();        // ✅ Find the rider_service_area record based on rider_id and old service_area_id        $riderServiceArea = RiderServiceArea::where('rider_id', $rider->id)            ->where('service_area_id', $request->id)            ->first();        // ✅ If not found, return a clear message        if (!$riderServiceArea) {            return response()->json([                'status' => false,                'message' => 'Service area not found for this rider.'            ], 404);        }        // ✅ Update the service_area_id with the new one        $riderServiceArea->update([            'service_area_id' => $request->area        ]);        // ✅ Load the updated service area relationship        $updatedServiceArea = new \App\Http\Resources\ServiceAreaResource($riderServiceArea->serviceArea);        // ✅ Return success response        return response()->json([            'status' => true,            'message' => 'Service area updated successfully.',            'data' => [                'service_area' => $updatedServiceArea            ]        ]);    } catch (\Exception $e) {        // ✅ Catch any unexpected errors        return response()->json([            'status' => false,            'message' => 'Something went wrong',            'error' => $e->getMessage()        ], 500);    }}//     public function updateServiceArea(Request $request)//     {//     try {//         $request->validate([//             'id' => 'required|exists